<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Countdown Timer</title>
    <script>
        const events = [
            { name: "Event 1", duration: 3600 }, // 1 hour
            { name: "Event 2", duration: 7200 }  // 2 hours
        ];

        function countdown(event, duration) {
            let interval = setInterval(() => {
                duration -= 1;
                updateUI(duration);

                if (duration < 15 * 60) {
                    if (duration >= 15 * 60) speak(`Hello, you have 15 minutes left for ${event.name}`);
                    if (duration >= 5 * 60) speak(`Hello, you have 5 minutes left for ${event.name}`);
                }

                if (duration <= 0) {
                    clearInterval(interval);
                    speak("This is the end for " + event.name);
                }
            }, 60000);
        }

        function updateUI(duration) {
            const minutes = Math.floor(duration / 60);
            const seconds = duration % 60;
            document.getElementById("timer").innerText = `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
        }

        function speak(text) {
            const synth = window.speechSynthesis;
            const utterance = new SpeechSynthesisUtterance(text);
            synth.speak(utterance);
        }

        window.onload = () => {
            events.forEach(event => {
                setTimeout(() => {
                    speak(`Hello, this is the start of ${event.name}`);
                    countdown(event, event.duration);
                }, (event.duration - 3600) * 1000); // Start 1 hour before the event
            });
        };
    </script>
</head>
<body>
    <h1>Countdown Timer</h1>
    <p id="timer"></p>
</body>
</html>
```

### Explanation:
- **Events**: An array of objects containing the event name and duration in seconds.
- **countdown function**: Manages the countdown for each event

