In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions. Here's a basic example using pipes:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    // Fork a new process
    pid = fork();
    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    // In the child process
    if (pid == 0) {
        // Close unused ends of the pipe
        close(pipefd[1]); // Close writing end in child

        // Duplicate file descriptors
        dup2(pipefd[0], STDIN_FILENO); // Input from pipe
        dup2(pipefd[0], STDOUT_FILENO); // Output to pipe

        // Close the pipe
        close(pipefd[0]);

        // Execute the process
        execlp("command", "command", NULL); // Replace "command" with your command
        std::cerr << "Exec failed" << std::endl;
        _exit(1);
    } else { // In the parent process
        // Close unused ends of the pipe
        close(pipefd[0]); // Close reading end in parent

        // Write to the pipe (if needed)
        // write(pipefd[1], "input", strlen("input"));

        // Close the writing end
        close(pipefd[1]);

        // Wait for the child to finish
        wait(NULL);
    }

    return 0;
}
```

This example uses a pipe to connect the child process's stdin and stdout to the parent's end of the pipe. You would replace `"command"` with the command you want to run in the child process. Note that the parent process can optionally write to the pipe if needed.
